request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?originalId ?normalizedId ?created WHERE {
  ?org a bboExt:Organization ;
       tai:organizationId ?orgId .
  FILTER(?orgId = "67e70970f0404a7e87122700ad26d87b")
  ?model a bboExt:Model ;
         tai:belongsTo ?org ;
         bbo:name ?modelName ;
         tai:originalId ?originalId ;
         tai:normalizedId ?normalizedId ;
         tai:modelCreated ?created .
  FILTER(
    CONTAINS(LCASE(STR(?modelName)), "bike") ||
    CONTAINS(LCASE(STR(?modelName)), "rental") ||
    CONTAINS(LCASE(STR(?modelName)), "insur") ||
    CONTAINS(LCASE(STR(?modelName)), "insurance")
  )
}
ORDER BY DESC(?created)
LIMIT 25
